// Test the toggleActive function directly
const path = require('path');

// We'll test the core validation logic
const { pluginNamePattern } = require('/workspace/src/constants');

console.log('\n=== Testing Plugin Validation ===\n');

// Create a mock toggleActive that has the validation logic
async function toggleActive(id) {
  if (!pluginNamePattern.test(id)) {
    throw new Error('[[error:invalid-plugin-id]]');
  }
  return { id: id, active: true };
}

// Test cases from test/plugins.js
const testCases = [
  {
    id: '\t\nnodebb-plugin',
    shouldReject: true,
    description: 'should reject plugin ID with tabs and newlines'
  },
  {
    id: 'notaplugin',
    shouldReject: true,
    description: 'should reject invalid plugin ID'
  },
  {
    id: 'nodebb-plugin-imgur',
    shouldReject: false,
    description: 'should accept valid plugin ID'
  }
];

async function runTests() {
  let passed = 0;
  let failed = 0;

  for (const test of testCases) {
    try {
      await toggleActive(test.id);

      if (test.shouldReject) {
        console.log(`❌ FAIL: ${test.description}`);
        console.log(`   Expected to reject "${test.id}" but it was accepted\n`);
        failed++;
      } else {
        console.log(`✅ PASS: ${test.description}`);
        console.log(`   Correctly accepted "${test.id}"\n`);
        passed++;
      }
    } catch (err) {
      if (test.shouldReject && err.message === '[[error:invalid-plugin-id]]') {
        console.log(`✅ PASS: ${test.description}`);
        console.log(`   Correctly rejected "${test.id}"\n`);
        passed++;
      } else {
        console.log(`❌ FAIL: ${test.description}`);
        console.log(`   Error: ${err.message}\n`);
        failed++;
      }
    }
  }

  console.log(`\n=== Results ===`);
  console.log(`Passed: ${passed}/${testCases.length}`);
  console.log(`Failed: ${failed}/${testCases.length}`);

  if (failed === 0) {
    console.log('\n✅ All validation tests passed!');
    process.exit(0);
  } else {
    console.log('\n❌ Some tests failed');
    process.exit(1);
  }
}

runTests().catch(err => {
  console.error('Test execution error:', err);
  process.exit(1);
});
EOF
