   104→	Plugins.libraryPaths.length = 0;
   105→	Plugins.loadedPlugins.length = 0;
   106→
   107→	await user.addInterstitials();
   108→
   109→	const paths = await Plugins.getPluginPaths();
   110→	for (const path of paths) {
   111→		/* eslint-disable no-await-in-loop */
   112→		await Plugins.loadPlugin(path);
   113→	}
   114→
   115→	// If some plugins are incompatible, throw the warning here
   116→	if (Plugins.versionWarning.length && nconf.get('isPrimary')) {
   117→		console.log('');
   118→		winston.warn('[plugins/load] The following plugins may not be compatible with your version of NodeBB. This may cause unintended behaviour or crashing. In the event of an unresponsive NodeBB caused by this plugin, run `./nodebb reset -p PLUGINNAME` to disable it.');
   119→		for (let x = 0, numPlugins = Plugins.versionWarning.length; x < numPlugins; x += 1) {
   120→			console.log(`${chalk.yellow('  * ') + Plugins.versionWarning[x]}`);
   121→		}
   122→		console.log('');
   123→	}
   124→
   125→	// Core hooks
   126→	posts.registerHooks();
   127→
   128→	// Deprecation notices
   129→	Plugins.hooks._deprecated.forEach((deprecation, hook) => {
   130→		if (!deprecation.affected || !deprecation.affected.size) {
   131→			return;
   132→		}
   133→
   134→		const replacement = deprecation.hasOwnProperty('new') ? `Please use ${chalk.yellow(deprecation.new)} instead.` : 'There is no alternative.';
   135→		winston.warn(`[plugins/load] ${chalk.white.bgRed.bold('DEPRECATION')} The hook ${chalk.yellow(hook)} has been deprecated as of ${deprecation.since}, and slated for removal in ${deprecation.until}. ${replacement} The following plugins are still listening for this hook:`);
   136→		deprecation.affected.forEach(id => console.log(`  ${chalk.yellow('*')} ${id}`));
   137→	});
   138→
   139→	// Lower priority runs earlier
   140→	Object.keys(Plugins.loadedHooks).forEach((hook) => {
   141→		Plugins.loadedHooks[hook].sort((a, b) => a.priority - b.priority);
   142→	});
   143→
   144→	// Post-reload actions
   145→	await posts.configureSanitize();
   146→};
