   154→Plugins.get = async function (id) {
   155→	const url = `${nconf.get('registry') || 'https://packages.nodebb.org'}/api/v1/plugins/${id}`;
   156→	const { response, body } = await request.get(url);
   157→	if (!response.ok) {
   158→		console.log(response);
   159→		throw new Error(`[[error:unable-to-load-plugin, ${id}]]`);
   160→	}
   161→	let normalised = await Plugins.normalise([body ? body.payload : {}]);
   162→	normalised = normalised.filter(plugin => plugin.id === id);
   163→	return normalised.length ? normalised[0] : undefined;
   164→};
