   195→Plugins.normalise = async function (apiReturn) {
   196→	const pluginMap = {};
   197→	const { dependencies } = require(paths.installPackage);
   198→	apiReturn = Array.isArray(apiReturn) ? apiReturn : [];
   199→	apiReturn.forEach((packageData) => {
   200→		packageData.id = packageData.name;
   201→		packageData.installed = false;
   202→		packageData.active = false;
   203→		packageData.url = packageData.url || (packageData.repository ? packageData.repository.url : '');
   204→		pluginMap[packageData.name] = packageData;
   205→	});
   206→
   207→	let installedPlugins = await Plugins.showInstalled();
   208→	installedPlugins = installedPlugins.filter(plugin => plugin && !plugin.system);
   209→
   210→	installedPlugins.forEach((plugin) => {
   211→		// If it errored out because a package.json or plugin.json couldn't be read, no need to do this stuff
   212→		if (plugin.error) {
   213→			pluginMap[plugin.id] = pluginMap[plugin.id] || {};
   214→			pluginMap[plugin.id].installed = true;
   215→			pluginMap[plugin.id].error = true;
   216→			return;
   217→		}
   218→
   219→		pluginMap[plugin.id] = pluginMap[plugin.id] || {};
   220→		pluginMap[plugin.id].id = pluginMap[plugin.id].id || plugin.id;
   221→		pluginMap[plugin.id].name = plugin.name || pluginMap[plugin.id].name;
   222→		pluginMap[plugin.id].description = plugin.description;
   223→		pluginMap[plugin.id].url = pluginMap[plugin.id].url || plugin.url;
   224→		pluginMap[plugin.id].installed = true;
   225→		pluginMap[plugin.id].isTheme = themeNamePattern.test(plugin.id);
   226→		pluginMap[plugin.id].error = plugin.error || false;
   227→		pluginMap[plugin.id].active = plugin.active;
   228→		pluginMap[plugin.id].version = plugin.version;
   229→		pluginMap[plugin.id].settingsRoute = plugin.settingsRoute;
   230→		pluginMap[plugin.id].license = plugin.license;
   231→
   232→		// If install/package.json defines a version to use, stick to that
   233→		if (dependencies.hasOwnProperty(plugin.id) && semver.valid(dependencies[plugin.id])) {
   234→			pluginMap[plugin.id].latest = dependencies[plugin.id];
   235→		} else {
   236→			pluginMap[plugin.id].latest = pluginMap[plugin.id].latest || plugin.version;
   237→		}
   238→		try {
   239→			pluginMap[plugin.id].outdated = semver.gt(pluginMap[plugin.id].latest, pluginMap[plugin.id].version);
   240→		} catch (err) {
   241→			winston.error(`plugin ID=${plugin.id}, latest=${pluginMap[plugin.id].latest}, version=${pluginMap[plugin.id].version},\n${err.stack}`);
   242→			throw err;
   243→		}
   244→	});
   245→
   246→	if (nconf.get('plugins:active')) {
   247→		nconf.get('plugins:active').forEach((id) => {
   248→			pluginMap[id] = pluginMap[id] || {};
   249→			pluginMap[id].active = true;
   250→		});
   251→	}
   252→
   253→	const pluginArray = Object.values(pluginMap);
   254→
   255→	pluginArray.sort((a, b) => {
   256→		if (a.name > b.name) {
   257→			return 1;
   258→		} else if (a.name < b.name) {
   259→			return -1;
   260→		}
   261→		return 0;
   262→	});
   263→
   264→	return pluginArray;
   265→};
