   269→Plugins.showInstalled = async function () {
   270→	const dirs = await fs.promises.readdir(Plugins.nodeModulesPath);
   271→
   272→	let pluginPaths = await findNodeBBModules(dirs);
   273→	pluginPaths = pluginPaths.map(dir => path.join(Plugins.nodeModulesPath, dir));
