// Test the validation logic without needing the database
const path = require('path');
const { pluginNamePattern } = require('/workspace/src/constants');

// Create a mock Plugins.toggleActive function with the validation logic
const createToggleActive = () => {
  return async function (id) {
    if (!pluginNamePattern.test(id)) {
      throw new Error('[[error:invalid-plugin-id]]');
    }
    return { id: id, active: true };
  };
};

const toggleActive = createToggleActive();

// Test cases
const testCases = [
  { id: '\t\nnodebb-plugin', shouldFail: true, desc: 'invalid: contains whitespace' },
  { id: 'notaplugin', shouldFail: true, desc: 'invalid: wrong format' },
  { id: 'nodebb-plugin-imgur', shouldFail: false, desc: 'valid: standard plugin' },
  { id: 'nodebb-widget-test', shouldFail: false, desc: 'valid: widget' },
  { id: '@nodebb/nodebb-plugin-abc', shouldFail: false, desc: 'valid: scoped plugin' },
  { id: 'nodebb-theme-zenith', shouldFail: false, desc: 'valid: theme' },
  { id: 'nodebb-rewards-awesome', shouldFail: false, desc: 'valid: rewards' },
];

console.log('\nValidation Test Results:');
console.log('========================\n');

let passed = 0;
let failed = 0;

testCases.forEach(async (test) => {
  try {
    const result = await toggleActive(test.id);
    if (test.shouldFail) {
      console.log(`✗ FAIL: "${test.id}" (${test.desc})`);
      console.log(`  Expected error but got: ${JSON.stringify(result)}\n`);
      failed++;
    } else {
      console.log(`✓ PASS: "${test.id}" (${test.desc})`);
      console.log(`  Successfully activated plugin\n`);
      passed++;
    }
  } catch (err) {
    if (test.shouldFail && err.message === '[[error:invalid-plugin-id]]') {
      console.log(`✓ PASS: "${test.id}" (${test.desc})`);
      console.log(`  Correctly rejected with error: ${err.message}\n`);
      passed++;
    } else {
      console.log(`✗ FAIL: "${test.id}" (${test.desc})`);
      console.log(`  Error: ${err.message}\n`);
      failed++;
    }
  }
});

console.log('\nSummary: ' + passed + ' passed, ' + failed + ' failed');
EOF
